import React from 'react';
import Link from 'next/link';
import Dropdown from './Dropdown';

export type NavItemType = {
  title: string;
  href: string;
  dropdown?: Array<{ title: string; href: string }>;
};

interface NavItemProps {
  item: NavItemType;
  isActive: boolean;
  theme: string;
}

const NavItem = React.memo<NavItemProps>(({ item, isActive, theme }) => {
  return (
    <div className="relative group">
      <Link
        href={item.href}
        className={`relative px-3 py-2 text-foreground hover:text-red-500 transition-all duration-200 rounded-md ${
          isActive ? 'bg-red-500 text-white' : theme === 'light' ? 'hover:bg-red-100' : 'hover:bg-red-900'
        }`}
        aria-label={item.title}
      >
        {item.title}
      </Link>
      {item.dropdown && <Dropdown items={item.dropdown} />}
    </div>
  );
});

NavItem.displayName = 'NavItem';

export default NavItem;
